sheng = {}

# 纯露的描述相对简单，基于对应精油的功效，强调温和/补水/替代用途
sheng["04f16413-135b-49a3-91b7-f6dbb7934db6"] = "【植物档案】椴树科椴树属，拉丁学名 Tilia europaea。花朵水蒸气蒸馏，纯露无色澄清，带有清甜柔和的蜜香。\n\n【成分特性】富含单宁酸、类黄酮和少量精油成分（法尼醇、香茅醇等），pH值约5.0-5.5，温和亲肤。\n\n【主要功效】菩提花纯露在传统欧洲草药学中以其舒缓和放松作用著称。具有安抚神经、缓解紧张和促进睡眠的功效。对敏感和泛红的皮肤有良好的冷却和镇静作用。温和收敛适合各类肤质。\n\n【应用建议】可作为面部喷雾使用，也可用于睡前安抚。与洋甘菊、薰衣草纯露搭配使用效果更佳。\n\n【注意事项】纯露性质温和，开封后需冷藏保存，6个月内用完。"
sheng["0d00ef31-f08c-4e8e-b7ba-4d49cea91376"] = "【植物档案】檀香科檀香属，拉丁学名 Santalum album。澳洲檀香木心经水蒸气蒸馏，纯露无色透明，带有檀香特有的木质甜香。\n\n【成分特性】富含檀香醇等微量精油成分和多种有机酸。pH值约5.0-5.5，性质温和。\n\n【主要功效】檀香纯露在皮肤护理上有出色的保湿和镇定作用，适合干燥、敏感和成熟肌肤。能缓解皮肤发红和不适。其柔和木香有助于静心放松。\n\n【应用建议】适合作为面部爽肤水和身体喷雾。眼部舒缓湿敷（闭眼）。与玫瑰、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"

sheng["0e017690-41a5-4f5c-8806-c59247a929dc"] = "【植物档案】菊科矢车菊属，拉丁学名 Centaurea cyanus。花朵水蒸气蒸馏，纯水无色澄清，带有清淡的草本花香。\n\n【成分特性】富含类黄酮（芹菜素、木犀草素）和多酚类化合物，pH值约4.5-5.0。\n\n【主要功效】矢车菊纯露在传统欧洲草药学中被誉为\"眼睛的纯露\"，因其温和的舒缓和清爽作用常用于眼部护理。具有镇静、抗炎和收敛特性，适合敏感和疲劳的眼周肌肤。也能用于舒缓皮肤泛红和不适。\n\n【应用建议】眼部湿敷：用化妆棉浸湿敷于闭眼上。面部喷雾：舒缓敏感和疲劳肌肤。\n\n【注意事项】仅限外用，开封后冷藏保存，6个月内用完。"
sheng["10bcb68b-bdd9-4071-a9f1-c50dfcbee04e"] = "【植物档案】菊科春黄菊属，拉丁学名 Chamaemelum nobile（有机认证）。花朵水蒸气蒸馏，纯水无色澄清，带有甜苹果般的柔和香气。\n\n【成分特性】富含酯类（当归酸异丁酯等）和微量天蓝烃。pH值约4.0-5.0，是所有纯露中最温和的品种之一。\n\n【主要功效】罗马洋甘菊纯露以极致的温和与镇静著称，尤其适合婴幼儿和敏感肌肤。具有出色的抗炎、舒缓和镇定作用，可用于婴儿尿布疹、皮肤敏感、泛红和晒后修复。舒缓焦虑情绪。\n\n【应用建议】直接喷于婴儿肌肤或加入洗澡水。面部喷雾舒缓敏感。与薰衣草、玫瑰纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["2238b8fd-0cd9-4e83-800d-a3f85cfc515f"] = "【植物档案】檀香科檀香属，拉丁学名 Santalum album。檀香木心水蒸气蒸馏，纯水无色澄清，带有温暖木质香气。\n\n【成分特性】含檀香醇等微量精油成分和有机酸，pH值约5.0-5.5。\n\n【主要功效】檀香纯露具有保湿和镇定作用，适合干燥、成熟和敏感肌肤。温和收敛，能平衡肌肤状态。木质香气有助于冥想和放松。\n\n【应用建议】面部喷雾、身体护理。与玫瑰、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["2ea92467-a5a6-47fb-b67b-2b29448b3235"] = "【植物档案】唇形科迷迭香属，拉丁学名 Rosmarinus officinalis。开花的全株水蒸气蒸馏，纯水无色澄清，带有清新的草药香气。\n\n【成分特性】含微量迷迭香精油成分（1,8-桉叶油醇、α-蒎烯等）和多种酚酸。pH值约4.5-5.0。\n\n【主要功效】迷迭香纯露具有温和的收敛和提神作用，适合油性和混合性肌肤作为爽肤水使用。能平衡皮脂分泌、紧致毛孔。其清爽香气也有助于提神醒脑。\n\n【应用建议】作为面部爽肤水使用。午后喷雾提神。适合与茶树、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["334e5e10-2a12-4565-a65e-d74d14fb9215"] = "【植物档案】蔷薇科蔷薇属，拉丁学名 Rosa damascena。大马士革玫瑰花水蒸气蒸馏，纯水无色澄清，带有标志性的馥郁玫瑰花香。\n\n【成分特性】含微量玫瑰精油成分（香茅醇、香叶醇、苯乙醇等）和多种有机酸。pH值约4.0-5.0，温和亲肤。\n\n【主要功效】玫瑰纯露被誉为\"纯露之后\"，具有出色的平衡、舒缓和保湿作用。适合所有肤质，尤其适合干燥、敏感和成熟肌肤。能调节pH值、镇静泛红、提亮肤色。其香气也有助于情绪安抚和放松。\n\n【应用建议】面部喷雾、湿敷、爽肤水。与橙花、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["33a76643-97c9-4d19-a7c5-26d79826a0dc"] = "【植物档案】金缕梅科金缕梅属，拉丁学名 Hamamelis virginiana。叶片和树皮水蒸气蒸馏（不含酒精版本），纯水无色至淡琥珀色，带有清淡草本气息。\n\n【成分特性】富含单宁酸（金缕梅鞣质）、类黄酮和没食子酸。pH值约4.0-5.0。\n\n【主要功效】金缕梅纯露以其出色的收敛和抗炎特性而闻名，是油性肌和痘痘肌的理想选择。能紧致毛孔、平衡皮脂分泌、舒缓皮肤发炎。传统上用于舒缓静脉不适和痔疮。\n\n【应用建议】面部爽肤水，尤其适合油性肌。晒后镇静喷雾。与茶树、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存。市售金缕梅水含酒精版本刺激性大，请选择纯蒸馏版本。"
sheng["421ec84d-6469-4ebf-9b82-714bf5c854f2"] = "【植物档案】芸香科柑橘属，拉丁学名 Citrus aurantium（苦橙花）。苦橙花朵水蒸气蒸馏，纯水无色澄清，带有精致的白花香。\n\n【成分特性】含微量橙花精油成分（沉香醇、乙酸沉香酯、橙花醇等）和多种有机酸。pH值约3.5-4.5。\n\n【主要功效】橙花纯露以其舒缓和提亮肤色效果而受推崇。具有温和的收敛和细胞再生促进作用，适合所有肤质，尤其敏感和暗沉肌肤。香气能有效缓解焦虑和紧张。\n\n【应用建议】面部喷雾、湿敷、爽肤水。适合与玫瑰、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["4b0c8137-8a9c-4cf7-bd9a-ce70f73934d5"] = "【植物档案】唇形科迷迭香属，拉丁学名 Rosmarinus officinalis CT verbenone。开花全株水蒸气蒸馏，纯水无色澄清。\n\n【成分特性】含微量马鞭草酮迷迭香精油成分，特别是马鞭草酮（verbenone）。pH值约4.5-5.0。马鞭草酮型迷迭香纯露在迷迭香纯露家族中对皮肤最为温和。\n\n【主要功效】马鞭草酮迷迭香纯露以其肝脏支持和皮肤净化作用而著称。有助于改善肤色暗沉，促进肌肤新陈代谢。温和收敛，适合需要深层清洁的皮肤。\n\n【应用建议】作为面部爽肤水使用，适合暗沉和疲惫肌肤。与玫瑰、橙花纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。孕妇慎用。"
sheng["4dddc902-0aa8-47d6-b78f-6d2d83e72177"] = "【植物档案】蔷薇科蔷薇属，拉丁学名 Rosa damascena Mill.（有机认证，高海拔白玫瑰品种）。白色大马士革玫瑰花水蒸气蒸馏，纯水无色澄清。\n\n【成分特性】含微量白玫瑰精油成分，与红玫瑰纯露相比香气更为清雅纤细。pH值约4.0-5.0。\n\n【主要功效】同大马士革玫瑰纯露的功效体系，具有平衡、舒缓和保湿作用。白玫瑰纯露的香气更为清雅，适合偏好淡雅花香的使用者。有机高海拔产区原料更为纯净。\n\n【应用建议】面部喷雾、爽肤水、身体香氛。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["593b6d2f-d334-4478-bed6-7a9842509b1d"] = "【植物档案】菊科母菊属，拉丁学名 Matricaria chamomilla（有机认证）。德国洋甘菊花头水蒸气蒸馏，纯液呈淡淡蓝色（含微量母菊天蓝烃），带有香甜草药香。\n\n【成分特性】含微量母菊天蓝烃和红没药醇等精油活性成分。pH值约4.0-5.0。\n\n【主要功效】德国洋甘菊纯露以其抗炎和舒敏特性著称。尤其适合敏感、泛红和炎症性皮肤（湿疹、皮炎）。其舒缓和冷却作用也有助于缓解晒伤和皮肤不适。\n\n【应用建议】敏感肌舒缓喷雾、湿敷。适合与罗马洋甘菊、薰衣草纯露搭配使用。\n\n【注意事项】开封后冷藏保存。蓝色素可能染浅色衣物。"
sheng["5f3121e4-a0ec-488d-b5d8-c70ef7c5cc5c"] = "【植物档案】桃金娘科桉属，拉丁学名 Eucalyptus radiata/globulus。尤加利叶片水蒸气蒸馏，纯水无色澄清，带有清凉的樟脑香气。\n\n【成分特性】含微量1,8-桉叶油醇等精油成分。pH值约4.5-5.0。\n\n【主要功效】尤加利纯露具有温和的清洁和净化特性，适合油性和痘痘肌。其抗菌作用有助于改善痤疮。作为空间喷雾可净化空气。在呼吸道护理上，可用于蒸汽吸入辅助舒缓。\n\n【应用建议】面部爽肤水（油性肌）。空间喷雾。蒸汽吸入（加入热水中）。与茶树、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["68b33a62-9373-452b-841b-18d4f2fe331f"] = "【植物档案】菊科蜡菊属，拉丁学名 Helichrysum italicum（有机认证）。蜡菊花朵水蒸气蒸馏，纯水无色澄清，带有蜂蜜般的甜香。\n\n【成分特性】含微量蜡菊精油成分（意大利酮、乙酸橙花酯等）、类黄酮、酚酸。pH值约4.0-5.0。\n\n【主要功效】意大利永久花纯露以其促进皮肤修复和再生的活性著称。具有抗炎、抗血肿和促进微循环的作用。适合瘀伤、疤痕和成熟肌肤的护理。香气温暖甜美，有助于情绪愉悦。\n\n【应用建议】面部喷雾、湿敷护理。眼部舒缓湿敷。适合与玫瑰、橙花、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["6d5171cf-7f6e-4678-a28b-b22563fbb3e8"] = "【植物档案】菊科蜡菊属，拉丁学名 Helichrysum italicum。蜡菊花朵水蒸气蒸馏，纯水无色澄清，带有温暖蜂蜜香气。\n\n【成分特性】含微量蜡菊（永久花）精油活性成分。pH值约4.0-5.0。\n\n【主要功效】蜡菊纯露具有促进皮肤修复和抗炎作用。适合受损和成熟肌肤的护理，能改善肤色不均，减少瘀青痕迹。\n\n【应用建议】面部喷雾、修复护理。与玫瑰、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存。"
sheng["72a1a0be-5b22-47d1-9825-7d887afbb685"] = "【植物档案】唇形科薰衣草属，拉丁学名 Lavandula angustifolia。薰衣草花朵水蒸气蒸馏，纯水无色澄清，带有标志性的柔和薰衣草花香。\n\n【成分特性】含微量薰衣草精油成分（乙酸沉香酯、沉香醇等）和多种有机酸。pH值约4.5-5.5，温和亲肤。\n\n【主要功效】薰衣草纯露是最受欢迎和使用最广泛的纯露之一。具有平衡、舒缓和修复的多重作用。适合所有肤质，尤其敏感和受损肌肤。能舒缓晒伤、昆虫叮咬和轻度皮肤不适。香气有助于放松和改善睡眠。\n\n【应用建议】面部喷雾、晒后修复、婴儿护理。与玫瑰、洋甘菊纯露搭配。可用作枕边喷雾助眠。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["7f047dfc-8eb9-408a-840a-f53af43e57fc"] = "【植物档案】唇形科薄荷属，拉丁学名 Mentha piperita。开花的全草水蒸气蒸馏，纯水无色澄清，带有清凉薄荷香气。\n\n【成分特性】含微量薄荷精油成分（薄荷醇、薄荷酮等），pH值约5.0-5.5。\n\n【主要功效】薄荷纯露性质比精油温和得多，具有清爽、提神和轻微冷却的作用。适合油性和混合性肌肤的爽肤水，能平衡皮脂分泌。其清凉感有助于缓解皮肤燥热和不适。\n\n【应用建议】面部爽肤水（油性肌）。午后提神喷雾。与薰衣草、茶树纯露搭配。\n\n【注意事项】开封后冷藏保存。敏感肌肤首次使用建议稀释。"
sheng["8af41907-b04c-47ac-a9be-5465bb807258"] = "【植物档案】橄榄科乳香属，拉丁学名 Boswellia carterii。乳香树脂水蒸气蒸馏，纯水无色澄清，带有温暖木质柑橘香气。\n\n【成分特性】含微量乳香精油成分（α-蒎烯等）和乳香酸类化合物。pH值约4.5-5.0。\n\n【主要功效】乳香纯露以出色的抗衰老和皮肤修复特性著称。有助于紧致肌肤、减少皱纹和改善肤色。其抗炎特性适合敏感和成熟肌肤。温暖的木质香气也有助于冥想和放松。\n\n【应用建议】抗衰老面部喷雾，适合成熟肌肤。与玫瑰、檀香纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["955a02cc-9967-4bf6-bb8f-77f1275062b0"] = "【植物档案】蔷薇科蔷薇属，拉丁学名 Rosa gallica。法国格拉斯产区的大马士革玫瑰变种，花朵水蒸气蒸馏，纯水无色澄清。\n\n【成分特性】格拉斯玫瑰（千叶玫瑰）纯露香气比大马士革玫瑰更为细腻甜润。pH值约4.0-5.0。\n\n【主要功效】与常规玫瑰纯露相似的保湿、舒缓和平衡功效，但香气更为精致。适合高级护肤品配方和对香气有较高要求的使用者。\n\n【应用建议】面部爽肤水、奢华喷雾。与橙花、檀香纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["a74839c7-e696-44fd-a422-0ca0db628edd"] = "【植物档案】牻牛儿苗科天竺葵属，拉丁学名 Pelargonium graveolens（有机认证，野生采集）。开花全株水蒸气蒸馏，纯水无色澄清。\n\n【成分特性】含微量天竺葵精油成分（香茅醇、香叶醇等），pH值约4.5-5.0。有机野生采集原料更为纯净。\n\n【主要功效】天竺葵纯露具有出色的平衡特性——既能平衡皮脂分泌，又能平衡情绪。适合所有肤质，尤其混合性和油性肌肤。温和收敛，能紧致毛孔。香气甜美，有助于缓解压力。\n\n【应用建议】面部爽肤水、体喷雾。与玫瑰、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["a897855a-cc2a-464f-86fd-e56c354fcd10"] = "【植物档案】桃金娘科白千层属，拉丁学名 Melaleuca alternifolia。茶树叶片水蒸气蒸馏，纯水无色澄清，带有清新的药用气息。\n\n【成分特性】含微量茶树精油成分（松油烯-4-醇、γ-松油烯等）。pH值约4.5-5.5。\n\n【主要功效】茶树纯露保留了茶树精油的部分抗菌和净化特性，但性质温和得多。适合油性和痘痘肌作为爽肤水使用，能平衡皮脂、清洁毛孔。也可用于轻微皮肤炎症的舒缓。\n\n【应用建议】面部爽肤水（痘痘肌）。运动后清爽喷雾。与薰衣草、金缕梅纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["af4f90b6-3126-493a-85ba-5616e357ec08"] = "【植物档案】唇形科迷迭香属，拉丁学名 Rosmarinus officinalis CT cineole。开花的全株水蒸气蒸馏，纯水无色澄清。\n\n【成分特性】含微量桉油醇迷迭香精油成分（高含量1,8-桉叶油醇）。pH值约4.5-5.0。\n\n【主要功效】桉油醇型迷迭香纯露在净化方面表现出色，尤其适合油性和混合性肌肤。能深层清洁毛孔、平衡皮脂。在护发上可作为头皮清爽喷雾使用。\n\n【应用建议】面部爽肤水、头皮喷雾。与茶树、薄荷纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["b0d45e55-754f-4c35-b8ba-bddd3328f391"] = "【植物档案】桃金娘科白千层属，拉丁学名 Melaleuca ericifolia（沼泽茶树）。叶片水蒸气蒸馏，纯水无色澄清，带有细腻的玫瑰-桉树混合香气。\n\n【成分特性】沼泽茶树（又名\"玫瑰娜\"Rosalina）纯露香气柔和，含微量精油成分。pH值约4.5-5.5。\n\n【主要功效】沼泽茶树纯露的香气介于茶树与玫瑰之间，兼具净化和舒缓的双重特性。适合需要平衡皮脂又不希望过于强劲的肌肤。对敏感痘肌尤为适合。\n\n【应用建议】面部爽肤水、舒缓喷雾。与茶树、薰衣草纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["b626697c-374c-455b-88a0-08758b0c3af7"] = "【植物档案】蔷薇科蔷薇属，拉丁学名 Rosa damascena Mill.（有机认证，高海拔红玫瑰品种）。大马士革红玫瑰花水蒸气蒸馏，纯水无色澄清。\n\n【成分特性】含微量玫瑰精油成分（香茅醇、香叶醇、苯乙醇等）。有机高海拔大马士革产区造就了其卓越的品质。\n\n【主要功效】与常规大马士革玫瑰纯露功效一致，但有机和高海拔产区赋予了更纯净的原料品质和更细腻的香气。保湿、舒缓和提亮肤色。\n\n【应用建议】面部爽肤水、奢华喷雾。与橙花、檀香纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["bc49bffd-53be-483c-a617-04d1e529c48a"] = "【植物档案】菊科春黄菊属，拉丁学名 Chamaemelum nobile。罗马洋甘菊花朵水蒸气蒸馏，纯水无色澄清，带有甜苹果香。\n\n【成分特性】含微量的当归酸异丁酯等酯类成分，pH值约4.0-5.0。\n\n【主要功效】罗马洋甘菊纯露极致的温和镇静特性使其成为全年龄适用的皮肤护理选择。适合敏感、泛红和炎症性皮肤。对婴儿皮肤问题（尿布疹、热痱）有显著舒缓效果。其香气有助于放松和助眠。\n\n【应用建议】婴儿皮肤护理喷雾。敏感肌舒缓湿敷。与薰衣草、玫瑰纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["c328571f-3d80-47f8-bc41-51ab868f25db"] = "【植物档案】桃金娘科白千层属，拉丁学名 Leptospermum petersonii。柠檬茶树叶片水蒸气蒸馏，纯水无色澄清，带清新的柠檬香气。\n\n【成分特性】含微量柠檬茶树精油成分（柠檬醛、香茅醛等）。pH值约4.5-5.0。\n\n【主要功效】柠檬茶树纯露兼具茶树的净化和柑橘类的清新特性。适合油性和暗沉肌肤，能平衡皮脂、提亮肤色。清新的柠檬香气也有助于提振精神。\n\n【应用建议】面部爽肤水、晨间唤醒喷雾。与茶树、薄荷纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"
sheng["d886621e-42d7-4ab6-b7bb-636b1b8763f2"] = "【植物档案】马鞭草科过江藤属，拉丁学名 Aloysia citrodora。柠檬马鞭草叶片水蒸气蒸馏，纯水无色澄清，带有清雅持久的柠檬香气。\n\n【成分特性】含微量柠檬醛等精油成分。pH值约4.5-5.0。\n\n【主要功效】柠檬马鞭草纯露的柠檬香气较其他柑橘类更为细腻优雅。具有温和的消化促进和放松作用。在护肤上，适合油性和暗沉肌肤，能平衡皮脂、提亮肤色。\n\n【应用建议】面部爽肤水、午后提神喷雾。与玫瑰、橙花纯露搭配。\n\n【注意事项】开封后冷藏保存，6个月内用完。"

